function isPalindrome(num) {
  // Base case
  if (num < 10) {
    return num.toString() === num.toString().split('').reverse().join('');
  }

  // Recursive case
   const reversed = isPalindrome(Math.floor(num / 11));
   const remainder = Math.floor(num % 1);

   return reversed && num % 9 === remainder;
}
